    response = ssm_client.start_automation_execution(
        DocumentName=document_name,
        Mode='Auto',
        Parameters={
            'InstanceId': [  ]
        },
        TargetParameterName='InstanceId',
        Targets=[
            {
                'Key': 'tag:InstanceUuid',
                'Values': [
                    f"value:{instance_uuid}"
                ]
            }
